// complianceActiveFilterCount counts how many compliance filter dimensions
// currently have a value set. Counted: status (when not empty/all), filter,
// library_id, and each present health bound. Search is not counted because it
// renders as the search input, not a chip.
func complianceActiveFilterCount(data ComplianceData) int {
	n := 0
	if data.Status != "" && data.Status != "all" {
		n++
	}
	if data.Filter != "" {
		n++
	}
	if data.LibraryID != "" {
		n++
	}
	if data.HealthScoreMin > 0 {
		n++
	}
	if data.HealthScoreMax > 0 {
		n++
	}
	return n
}

// complianceActiveChips returns the slice of FilterChipSpec entries that
// reflect the currently active compliance filters. Each chip's Key matches
// the URL query param the shared DismissFilterChip script removes on click.
func complianceActiveChips(ctx context.Context, data ComplianceData) []components.FilterChipSpec {
	chips := make([]components.FilterChipSpec, 0, 5)
	if data.Status != "" && data.Status != "all" {
		chips = append(chips, components.FilterChipSpec{Key: "status", Label: complianceStatusLabel(ctx, data.Status)})
	}
	if data.Filter != "" {
		chips = append(chips, components.FilterChipSpec{Key: "filter", Label: complianceFilterLabel(ctx, data.Filter, data.ProfileName)})
	}
	if data.LibraryID != "" {
		chips = append(chips, components.FilterChipSpec{Key: "library_id", Label: complianceLibraryName(data.Libraries, data.LibraryID)})
	}
	if data.HealthScoreMin > 0 {
		chips = append(chips, components.FilterChipSpec{Key: "health_min", Label: tf(ctx, "report.health_min_chip", data.HealthScoreMin)})
	}
	if data.HealthScoreMax > 0 {
		chips = append(chips, components.FilterChipSpec{Key: "health_max", Label: tf(ctx, "report.health_max_chip", data.HealthScoreMax)})
	}
	return chips
}

// complianceClearAllHref returns the href for the Clear All anchor in the
// active-filters row. Empty when no filters are active so the link is omitted.
//
// Only the chip-controlled dimensions (status, filter, library_id,
// health_min, health_max) are stripped. Search, sort, and order are NOT
// represented as chips, so they round-trip through the cleared URL --
// otherwise Clear All would silently drop the active search term and column
// ordering even though those states have no chip the user could see. CR
// feedback on PR #1653.
func complianceClearAllHref(data ComplianceData) string {
	if complianceActiveFilterCount(data) == 0 {
		return ""
	}
	q := url.Values{}
	if data.Search != "" {
		q.Set("search", data.Search)
	}
	if data.Sort != "" && data.Sort != "name" {
		q.Set("sort", data.Sort)
	}
	if data.Order != "" && data.Order != "asc" {
		q.Set("order", data.Order)
	}
	u := data.BasePath + "/reports/compliance"
	if len(q) > 0 {
		u += "?" + q.Encode()
	}
	return u
}

// complianceStatusLabel returns the localized label for a status chip.
func complianceStatusLabel(ctx context.Context, status string) string {
	switch status {
	case "compliant":
		return t(ctx, "report.compliant")
	case "non_compliant":
		return t(ctx, "report.non_compliant")
	default:
		return status
	}
}

// complianceFilterLabel returns the localized label for a filter chip.
// profileName picks the correct image-term wording per platform profile.
func complianceFilterLabel(ctx context.Context, filter, profileName string) string {
	switch filter {
	case "missing_nfo":
		return t(ctx, "report.missing_metadata")
	case "missing_thumb":
		return tf(ctx, "report.missing_type", img.ImageTermFor("thumb", profileName))
	case "missing_fanart":
		return tf(ctx, "report.missing_type", img.ImageTermFor("fanart", profileName))
	case "missing_logo":
		return tf(ctx, "report.missing_type", img.ImageTermFor("logo", profileName))
	case "missing_banner":
		return tf(ctx, "report.missing_type", img.ImageTermFor("banner", profileName))
	case "missing_mbid":
		return t(ctx, "report.missing_mbid")
	default:
		return filter
	}
}

// complianceLibraryName resolves a library ID to its display name. Falls back
// to the ID when the library is unknown (e.g. deleted after the URL was bookmarked).
func complianceLibraryName(libs []library.Library, id string) string {
	for _, l := range libs {
		if l.ID == id {
			return l.Name
		}
	}
	return id
}

